// Check upcoming CBAM deadlines against current date
// Deadlines to track: quarterly report submission, annual verification, factor updates
// Output: deadline objects with name, date, days remaining, priority
const today = new Date();
const deadlines = [
  { name: 'Q1 CBAM Report Due', date: '2026-04-30', priority: 'high' },
  { name: 'Q2 CBAM Report Due', date: '2026-07-31', priority: 'high' },
  { name: 'Q3 CBAM Report Due', date: '2026-10-31', priority: 'high' },
  { name: 'Q4 CBAM Report Due', date: '2027-01-31', priority: 'high' },
  { name: 'Default Values Review', date: '2026-12-31', priority: 'medium' }
];
const upcoming = deadlines.filter(d => {
  const diff = Math.ceil((new Date(d.date) - today) / (1000 * 60 * 60 * 24));
  return diff <= 30 && diff >= 0;
});
return upcoming.map(d => ({ json: { ...d, daysRemaining: Math.ceil((new Date(d.date) - today) / (1000 * 60 * 60 * 24)) } }));
